import{_ as e,o as d,c as r,ag as a}from"./chunks/framework.6MCaaFDc.js";const u=JSON.parse('{"title":"Networks & Internet — Quick Summary","description":"","frontmatter":{},"headers":[],"relativePath":"quick-study/networks-summary.md","filePath":"quick-study/networks-summary.md"}'),o={name:"quick-study/networks-summary.md"};function n(i,t,s,h,l,c){return d(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="networks-internet-—-quick-summary" tabindex="-1">Networks &amp; Internet — Quick Summary <a class="header-anchor" href="#networks-internet-—-quick-summary" aria-label="Permalink to &quot;Networks &amp; Internet — Quick Summary&quot;">​</a></h1><p>No prose. Tables and key facts only.</p><hr><h2 id="network-types" tabindex="-1">Network Types <a class="header-anchor" href="#network-types" aria-label="Permalink to &quot;Network Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Range</th><th>Example</th></tr></thead><tbody><tr><td>PAN</td><td>~10m</td><td>Bluetooth headset ↔ phone</td></tr><tr><td>HAN</td><td>One home</td><td>Home Wi-Fi</td></tr><tr><td>LAN</td><td>Building</td><td>School computer lab</td></tr><tr><td>MAN</td><td>City</td><td>City-wide Wi-Fi</td></tr><tr><td>WAN</td><td>Country/continent</td><td>Bank branch network</td></tr><tr><td>Internet</td><td>Global</td><td>The internet</td></tr></tbody></table><hr><h2 id="network-models" tabindex="-1">Network Models <a class="header-anchor" href="#network-models" aria-label="Permalink to &quot;Network Models&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Client-Server</th><th>Peer-to-Peer</th></tr></thead><tbody><tr><td>Dedicated server?</td><td>Yes</td><td>No</td></tr><tr><td>Cost</td><td>High</td><td>Low</td></tr><tr><td>Security</td><td>Centralised, high</td><td>Decentralised, low</td></tr><tr><td>Scale</td><td>Many computers</td><td>Best &lt; 10</td></tr><tr><td>Admin</td><td>One place</td><td>Each computer</td></tr><tr><td>Used in</td><td>Schools, businesses</td><td>Home networks</td></tr></tbody></table><hr><h2 id="topologies" tabindex="-1">Topologies <a class="header-anchor" href="#topologies" aria-label="Permalink to &quot;Topologies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topology</th><th>Shape</th><th>Single point of failure?</th><th>Cable?</th></tr></thead><tbody><tr><td>Star</td><td>Central switch + cables to each device</td><td>Switch</td><td>More</td></tr><tr><td>Bus</td><td>One cable, devices tap in</td><td>Main cable</td><td>Less</td></tr><tr><td>Ring</td><td>Circle</td><td>Any break</td><td>Moderate</td></tr><tr><td>Mesh</td><td>Everything connected to everything</td><td>No</td><td>Most</td></tr></tbody></table><p><strong>Modern choice:</strong> Star (switch-based)</p><hr><h2 id="network-hardware" tabindex="-1">Network Hardware <a class="header-anchor" href="#network-hardware" aria-label="Permalink to &quot;Network Hardware&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Device</th><th>Function</th></tr></thead><tbody><tr><td>NIC</td><td>Hardware enabling device to connect to network</td></tr><tr><td>Switch</td><td>Connects devices on SAME network; sends to specific device</td></tr><tr><td>Hub</td><td>Like switch but broadcasts to ALL (less efficient)</td></tr><tr><td>Router</td><td>Connects DIFFERENT networks; assigns IP (DHCP)</td></tr><tr><td>Modem</td><td>Converts digital ↔ analogue for phone line</td></tr><tr><td>WAP</td><td>Wireless Access Point — extends Wi-Fi coverage</td></tr><tr><td>Firewall</td><td>Filters network traffic for security</td></tr><tr><td>Repeater</td><td>Extends signal distance</td></tr></tbody></table><hr><h2 id="key-protocols" tabindex="-1">Key Protocols <a class="header-anchor" href="#key-protocols" aria-label="Permalink to &quot;Key Protocols&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Protocol</th><th>Port</th><th>Purpose</th></tr></thead><tbody><tr><td>HTTP</td><td>80</td><td>Web pages (unencrypted)</td></tr><tr><td>HTTPS</td><td>443</td><td>Web pages (SSL/TLS encrypted)</td></tr><tr><td>FTP</td><td>20/21</td><td>File transfer</td></tr><tr><td>SMTP</td><td>25</td><td>Send email</td></tr><tr><td>POP3</td><td>110</td><td>Download email (removes from server)</td></tr><tr><td>IMAP</td><td>143</td><td>Access email (stays on server)</td></tr><tr><td>DNS</td><td>53</td><td>Domain name → IP address</td></tr><tr><td>DHCP</td><td>67/68</td><td>Automatic IP address assignment</td></tr><tr><td>SSH</td><td>22</td><td>Secure remote access</td></tr></tbody></table><hr><h2 id="tcp-vs-udp" tabindex="-1">TCP vs UDP <a class="header-anchor" href="#tcp-vs-udp" aria-label="Permalink to &quot;TCP vs UDP&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>TCP</th><th>UDP</th></tr></thead><tbody><tr><td>Reliable?</td><td>Yes — acknowledgements</td><td>No</td></tr><tr><td>Ordered?</td><td>Yes</td><td>No</td></tr><tr><td>Speed</td><td>Slower</td><td>Faster</td></tr><tr><td>Use for</td><td>Web, email, FTP</td><td>Streaming, gaming, VoIP</td></tr></tbody></table><hr><h2 id="wi-fi-standards" tabindex="-1">Wi-Fi Standards <a class="header-anchor" href="#wi-fi-standards" aria-label="Permalink to &quot;Wi-Fi Standards&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Standard</th><th>Name</th><th>Max Speed</th></tr></thead><tbody><tr><td>802.11g</td><td>Wi-Fi 3</td><td>54 Mbps</td></tr><tr><td>802.11n</td><td>Wi-Fi 4</td><td>600 Mbps</td></tr><tr><td>802.11ac</td><td>Wi-Fi 5</td><td>3.5 Gbps</td></tr><tr><td>802.11ax</td><td>Wi-Fi 6</td><td>9.6 Gbps</td></tr></tbody></table><p>2.4 GHz = longer range, slower, more interference<br> 5 GHz = shorter range, faster, less interference</p><hr><h2 id="intranet-extranet-internet" tabindex="-1">Intranet / Extranet / Internet <a class="header-anchor" href="#intranet-extranet-internet" aria-label="Permalink to &quot;Intranet / Extranet / Internet&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Who accesses</th><th>Security</th></tr></thead><tbody><tr><td>Intranet</td><td>Internal only</td><td>Inside firewall</td></tr><tr><td>Extranet</td><td>Internal + authorised external</td><td>Controlled</td></tr><tr><td>Internet</td><td>Anyone</td><td>Public</td></tr></tbody></table><hr><h2 id="internet-concepts" tabindex="-1">Internet Concepts <a class="header-anchor" href="#internet-concepts" aria-label="Permalink to &quot;Internet Concepts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td>IP address</td><td>Unique identifier for device on network</td></tr><tr><td>IPv4</td><td>32-bit address (x.x.x.x) ~4.3B addresses</td></tr><tr><td>IPv6</td><td>128-bit address (hex groups) — virtually unlimited</td></tr><tr><td>Domain name</td><td>Human-readable address (www.google.com)</td></tr><tr><td>DNS</td><td>Translates domain names to IP addresses</td></tr><tr><td>ISP</td><td>Internet Service Provider</td></tr><tr><td>URL</td><td>Full web address (protocol + domain + path)</td></tr><tr><td>TLD</td><td>Top Level Domain (.com, .co.za, .org)</td></tr></tbody></table><hr><h2 id="web-evolution" tabindex="-1">Web Evolution <a class="header-anchor" href="#web-evolution" aria-label="Permalink to &quot;Web Evolution&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Web 1.0</th><th>Web 2.0</th><th>Web 3.0</th></tr></thead><tbody><tr><td>Type</td><td>Read only</td><td>Read-Write</td><td>Semantic/AI</td></tr><tr><td>Content creator</td><td>Website owner</td><td>Anyone (UGC)</td><td>Machine + user</td></tr><tr><td>Interaction</td><td>None</td><td>Social, comments, sharing</td><td>Personalised, decentralised</td></tr><tr><td>Example</td><td>Early websites</td><td>Facebook, YouTube</td><td>AI assistants, IoT</td></tr></tbody></table><hr><h2 id="ssl-tls-encryption" tabindex="-1">SSL/TLS Encryption <a class="header-anchor" href="#ssl-tls-encryption" aria-label="Permalink to &quot;SSL/TLS Encryption&quot;">​</a></h2><ol><li>Browser connects to HTTPS site</li><li>Server sends <strong>certificate</strong> (with public key)</li><li>Browser verifies certificate (Certificate Authority)</li><li>Browser encrypts session key with server&#39;s <strong>public key</strong></li><li>Server decrypts with <strong>private key</strong></li><li>All traffic encrypted with session key</li></ol><p>Public key = shared openly → encrypts<br> Private key = kept secret → decrypts</p><hr><h2 id="email-security-threats" tabindex="-1">Email Security Threats <a class="header-anchor" href="#email-security-threats" aria-label="Permalink to &quot;Email Security Threats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Threat</th><th>Description</th></tr></thead><tbody><tr><td>Spam</td><td>Unsolicited bulk email</td></tr><tr><td>Phishing</td><td>Fake email to steal credentials</td></tr><tr><td>Spear phishing</td><td>Targeted phishing using personal info</td></tr><tr><td>Spoofing</td><td>Faking sender identity</td></tr><tr><td>Malware attachment</td><td>Virus/trojan in email attachment</td></tr></tbody></table><hr><h2 id="cloud-service-models" tabindex="-1">Cloud Service Models <a class="header-anchor" href="#cloud-service-models" aria-label="Permalink to &quot;Cloud Service Models&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Model</th><th>What you get</th><th>Example</th></tr></thead><tbody><tr><td>IaaS</td><td>Virtual hardware (servers, storage)</td><td>AWS, Azure</td></tr><tr><td>PaaS</td><td>Development platform</td><td>Google App Engine</td></tr><tr><td>SaaS</td><td>Software via internet</td><td>MS 365, Gmail, Netflix</td></tr></tbody></table>',44)])])}const m=e(o,[["render",n]]);export{u as __pageData,m as default};
